// 2. Add HasApiTokens to User model
use Laravel\Sanctum\HasApiTokens;
class User extends Authenticatable {
    use HasApiTokens, HasFactory, Notifiable;
}

// 3. Login route – issue token
Route::post('/login', function (Request $request) {
    if (!Auth::attempt($request->only('email','password'))) {
        return response()->json(['message' => 'Invalid credentials'], 401);
    }
    $token = $request->user()->createToken('api-token')->plainTextToken;
    return response()->json(['token' => $token]);
});

// 4. Protected routes
Route::middleware('auth:sanctum')->group(function () {
    Route::get('/user', fn(Request $r) => $r->user());
    Route::apiResource('posts', PostController::class);
});

var builder = WebApplication.CreateBuilder(args);
builder.Services
    .AddAuthentication().AddJwtBearer();
builder.Services.AddAuthorization();
builder.Services.AddDbContext<Db>(o =>
    o.UseSqlite("Data Source=app.db"));

var app = builder.Build();
app.UseAuthentication();
app.UseAuthorization();

var items = app.MapGroup("/items").RequireAuthorization();
items.MapGet("/",    async (Db db) => await db.Items.ToListAsync());
items.MapGet("/{id}",async (int id, Db db) =>
    await db.Items.FindAsync(id) is Item i
        ? Results.Ok(i) : Results.NotFound());
items.MapPost("/", async (Item item, Db db) => {
    db.Items.Add(item);
    await db.SaveChangesAsync();
    return Results.Created($"/items/{item.Id}", item);
});
app.Run();
